    @staticmethod
    def detect_write_operation_in_query_fn() -> None:
        """
        Detect DataFrameWriter.save/saveAsTable/insertInto/jdbc inside a flow query function.
        """
        if PipelineSparkConnectMigrationTelemetry._is_enabled():
            # try/except guards against ImportError if this runtime PR is deployed before the
            # companion universe PR that adds detect_*_in_query_fn to dlt.overrides.
            try:
                from dlt.overrides import detect_write_operation_in_query_fn

                detect_write_operation_in_query_fn()
            except Exception:
                pass

